package com.securestack.util;import java.nio.charset.StandardCharsets;import java.security.*;public class Sanitizer{public static String mask(String s){if(s==null)return"";String x=s.replaceAll("AKIA[0-9A-Z]{12,}","AKIA************");x=x.replaceAll("(?i)(password|secret|api[_-]?key|token|authorization)(\\s*[:=]\\s*)[^\\s\\n\"']+","$1$2********");return x.length()>500?x.substring(0,500):x;}public static String sha256(String s){try{var md=MessageDigest.getInstance("SHA-256");byte[]b=md.digest(s.getBytes(StandardCharsets.UTF_8));StringBuilder sb=new StringBuilder();for(byte by:b)sb.append(String.format("%02x",by));return sb.toString();}catch(Exception e){return"";}}}
